import pytest
import requests
import uuid

BASE_URL = "http://localhost:8080"

@pytest.fixture
def clinician_headers():
    return <fixture: clinician_auth_headers>

@pytest.fixture
def existing_patient_id():
    return <fixture: existing_patient_id>

def test_create_observation_state_transition_nonexistent_to_created(clinician_headers, existing_patient_id):
    unique_id = str(uuid.uuid4())
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [{
                "system": "http://loinc.org",
                "code": "29463-7",
                "display": "Body weight"
            }]
        },
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "identifier": [{"value": unique_id}]
    }
    post_resp = requests.post(
        f"{BASE_URL}/Observation",
        json=payload,
        headers=clinician_headers
    )
    assert post_resp.status_code == 201
    obs_id = post_resp.json()["id"]
    get_resp = requests.get(
        f"{BASE_URL}/Observation/{obs_id}",
        headers=clinician_headers
    )
    assert get_resp.status_code == 200
    assert get_resp.json()["status"] == "final"
